#!/usr/bin/env python3"""Health Monitor -- 鍗忚皟浜哄仴搴锋鏌ョ郴缁?妫€娴?Agent 鏄惁瀛樻椿,瓒呮椂,澶辫触鐢ㄦ硶:    python health-monitor.py check <team_id>      # 妫€鏌ュ洟闃熷仴搴风姸鎬?    python health-monitor.py watch <team_id>       # 鎸佺画鐩戞帶(姣忕)    python health-monitor.py summary               # 鎵€鏈夊洟闃熸眹鎬?"""import jsonimport sysimport timefrom datetime import datetime, timedeltafrom pathlib import PathTEAM_BRAIN_ROOT = Path(__file__).parent.parent.parent / "shared" / "team-brain"HEARTBEAT_TIMEOUT = 120  # 瓒呰繃120绉掓棤蹇冭烦璁や负宸叉寕def load_team_status(team_id):    status_file = TEAM_BRAIN_ROOT / "teams" / f"{team_id}.json"    if not status_file.exists():        return None    with open(status_file, encoding="utf-8") as f:        return json.load(f)def check_agent_health(agent, now=None):    """妫€鏌ュ崟涓?Agent 鐨勫仴搴风姸鎬?""    if now is None:        now = datetime.now()        last_heartbeat = agent.get("last_heartbeat")    status = agent.get("status", "unknown")        if last_heartbeat:        try:            last = datetime.fromisoformat(last_heartbeat)            seconds_since = (now - last).total_seconds()            is_alive = seconds_since < HEARTBEAT_TIMEOUT            return {                "id": agent["id"],                "role": agent.get("role"),                "status": status,                "last_heartbeat": last_heartbeat,                "seconds_ago": int(seconds_since),                "is_alive": is_alive,                "is_stale": seconds_since > HEARTBEAT_TIMEOUT,                "is_failed": status in ("failed", "failed_with_error")            }        except:            pass        return {        "id": agent["id"],        "role": agent.get("role"),        "status": status,        "last_heartbeat": last_heartbeat,        "seconds_ago": None,        "is_alive": False,        "is_stale": True,        "is_failed": status in ("failed", "failed_with_error")    }def check_team_health(team_id):    """妫€鏌ユ暣涓洟闃熺殑鍋ュ悍鐘舵€?""    status = load_team_status(team_id)    if not status:        return {"error": f"team {team_id} not found"}        now = datetime.now()    agent_health = []    alive_count = 0    stale_count = 0    failed_count = 0        for agent in status.get("agents", []):        h = check_agent_health(agent, now)        agent_health.append(h)        if h["is_alive"]:            alive_count += 1        if h["is_stale"] and not h["is_failed"]:            stale_count += 1        if h["is_failed"]:            failed_count += 1        total = len(status.get("agents", []))        # 鏁翠綋鍋ュ悍璇勫垎    if total == 0:        health_score = 0    else:        health_score = alive_count / total        return {        "team_id": team_id,        "task": status.get("task"),        "phase": status.get("phase"),        "total_agents": total,        "alive": alive_count,        "stale": stale_count,        "failed": failed_count,        "health_score": round(health_score, 2),        "agents": agent_health,        "warnings": _generate_warnings(alive_count, stale_count, failed_count, total)    }def _generate_warnings(alive, stale, failed, total):    warnings = []    if stale > 0:        warnings.append(f"{stale} 涓?Agent 鏃犲績璺冲搷搴?鍙兘宸叉寕")    if failed > 0:        warnings.append(f"{failed} 涓?Agent 鎵ц澶辫触")    if alive < total:        warnings.append(f"鍥㈤槦涓嶅畬鏁?{alive}/{total} Agent 瀛樻椿")    return warningsdef get_all_teams():    """鑾峰彇鎵€鏈夊洟闃熺姸鎬?""    teams_dir = TEAM_BRAIN_ROOT / "teams"    if not teams_dir.exists():        return {}        teams = {}    for f in teams_dir.glob("*.json"):        team_id = f.stem        health = check_team_health(team_id)        teams[team_id] = health    return teamsdef print_team_health(health):    """鎵撳嵃鍥㈤槦鍋ュ悍鐘舵€?浜虹被鍙鏍煎紡)"""    print(f"\n{'='*60}")    print(f"鍥㈤槦: {health['team_id']}")    print(f"浠诲姟: {health.get('task', 'N/A')}")    print(f"闃舵: {health.get('phase', 'N/A')}")    print(f"鍋ュ悍璇勫垎: {health['health_score']} ({health['alive']}/{health['total_agents']} 瀛樻椿)")        if health.get("warnings"):        print("\n鈿狅笍  璀﹀憡:")        for w in health["warnings"]:            print(f"   - {w}")        print("\nAgent 鐘舵€?")    for a in health["agents"]:        alive_mark = "鉁? if a["is_alive"] else "鉁?        stale_mark = " (鏃犲績璺?" if a["is_stale"] else ""        failed_mark = " [澶辫触]" if a["is_failed"] else ""        secs = f" ({a['seconds_ago']}s鍓?" if a["seconds_ago"] else ""        print(f"   {alive_mark} {a['id']:12} | {a['status']:20} | {a['role']}{stale_mark}{failed_mark}{secs}")def main():    if len(sys.argv) < 2:        print(__doc__)        sys.exit(1)        cmd = sys.argv[1]        if cmd == "check":        team_id = sys.argv[2] if len(sys.argv) > 2 else None        if not team_id:            print("闇€瑕?team_id")            sys.exit(1)        health = check_team_health(team_id)        print_team_health(health)                # 杈撳嚭 JSON 鏍煎紡(渚夸簬绋嬪簭澶勭悊)        print("\n--- JSON Output ---")        print(json.dumps(health, ensure_ascii=False, indent=2))        elif cmd == "watch":        team_id = sys.argv[2] if len(sys.argv) > 2 else None        if not team_id:            print("闇€瑕?team_id")            sys.exit(1)                print(f"鎸佺画鐩戞帶 {team_id},鎸?Ctrl+C 鍋滄...")        try:            while True:                health = check_team_health(team_id)                # 娓呭睆(绠€鍗曞疄鐜?                print("\n" * 2)                print_team_health(health)                time.sleep(10)        except KeyboardInterrupt:            print("\n鐩戞帶鍋滄")        elif cmd == "summary":        teams = get_all_teams()        print(f"\n{'='*60}")        print(f"鎵€鏈夊洟闃熷仴搴风姸鎬?({len(teams)} 涓洟闃?")        print(f"{'='*60}")                for tid, health in teams.items():            print(f"\n{tid}: {health['health_score']} ({health['alive']}/{health['total_agents']})")            if health.get("warnings"):                for w in health["warnings"]:                    print(f"   鈿狅笍 {w}")        else:        print(f"鏈煡鍛戒护: {cmd}")        print(__doc__)        sys.exit(1)if __name__ == "__main__":    main()